-- ============================================================

UPDATE course_contents
SET week_plan = $week_data$[{"week":1,"theme":"秘密的语言——学习感受情绪","days_range":"1-7","goals":["引入“非言语情绪感知”的概念，激发学员的兴趣。学习并亲手制作本次实验的核心工具——“情绪闪卡”。理解并掌握实验的基本规则，并与家人完成第一次充满乐趣的“心灵感应”练习。"],"activities":[{"sequence":1,"day_label":"Day 1-2","day_range":"1-2","title_zh":"一个新“超能力”：你也能“读心”吗？","title_en":"A New 'Superpower': Can You 'Read' Minds?","duration":"约30分钟，可在2天内完成","content":"(任务时长：约30分钟，可在2天内完成)\n欢迎来到“伊卡洛斯计划”的第三个模块！这一次，我们将探索一个隐藏在我们每个人身上的、最神奇的“超能力”——感受他人情绪的能力。\n你有没有过这样的经历：有时候，你的好朋友一句话也没说，但你就是“感觉”到他今天不开心？或者，妈妈走进房间时，你立刻就感到了一种温暖和快乐？\n这种不用语言就能感受到的“悄悄话”，就是我们要探索的秘密。\n莉莉和汤姆是最好的朋友。他们有一个秘密：他们总能知道对方在想什么。\n有一天，老师在课堂上发回了画画作业。莉莉的画得了一朵小红花，她心里开心得像有蝴蝶在飞。她坐在汤姆后面，一句话也没说，只是静静地开心着。突然，前面的汤姆悄悄递过来一张纸条，上面画着一个大大的笑脸和一个庆祝的礼花。莉莉惊讶极了！\n还有一次，汤姆的宠物小仓鼠生病了，他非常难过。在课间休息时，他一个人坐在角落里，努力装作没事的样子。莉莉从教室另一头走过来，轻轻拍了拍他的肩膀，递给他一颗他最爱吃的糖。汤姆抬起头，惊讶地问：“你怎么知道我难过？”莉莉笑着说：“我就是‘感觉’到的呀！”\n这种神奇的“感觉”，就像他们之间有一条看不见的、彩色的“情绪电话线”。当一方开心时，电话线就闪耀着温暖的黄色；当一方难过时，它就变成了安静的蓝色。\n我们的任务：\n心灵探险家，你和你的家人、朋友之间，是否也存在着这样一条“情绪电话线”呢？本周，我们将学习如何“拨打”和“接听”这条特殊的电话。\n仔细阅读《莉莉和汤姆的秘密信号》的故事。\n回忆一下，你是否有过类似“感觉”到别-人情绪的经历？\n接受任务： 在下方的文本框中，输入你的探险家宣言。\n格式： “我是心灵探险家 [你的名字]，我准备好去发现情绪的秘密语言了！”\n分享你的经历： 简要描述一次你“感觉”到别人情绪的经历。"},{"sequence":3,"day_label":"Day 3-5","day_range":"3-5","title_zh":"制作你的“情绪工具箱”","title_en":"Crafting Your 'Emotion Toolkit'","duration":"约60分钟，可在3天内完成","content":"(任务时长：约60分钟，可在3天内完成)\n探险家，为了能科学地测试我们的“情绪电话线”，我们需要把那些看不见的情绪，变成可以拿在手里的、清晰的工具。这就是我们的**“情绪闪卡”（Feeling Flashcards）和“心灵感应日记”（Telepathy Diary）**。\n准备材料： 4张同样大小的硬纸卡片（比如扑克牌大小）、彩笔。\n绘制卡片： 在每一张卡片的正面，分别画出并写上以下四种核心情绪。请用你最富表现力的方式来画！\n开心 (Happy): 用黄色作为主色调，画一个大大的笑脸  。\n伤心 (Sad): 用蓝色作为主色调，画一个流着眼泪的悲伤脸  。\n生气 (Angry): 用红色作为主色调，画一个眉毛倒竖的生气脸  。\n平静 (Calm): 用绿色作为主色调，画一个表情宁静、放松的脸  。\n保持背面一致： 确保所有卡片的背面都是一样的，没有任何标记，这样在抽卡时才无法作弊。\n在你的笔记本里，画出下面的表格，用于记录我们接下来的实验。\n心灵感应实验 - 第 [ ] 轮\n \n日期\n \n“发送者”\n（例如：妈妈）\n“接收者”\n（例如：我）\n试验序号\n“发送”的情绪\n1\n（由发送者填写）\n2\n（由发送者填写）\n3\n（由发送者填写）\n...\n \n在画画时，用心去感受每一种情绪。当你画“开心”时，试着让自己也开心起来。\n理解日记中“发送者”和“接收者”的角色分工。\n提交你的“情绪闪卡”：\n将你制作的4张情绪闪卡正面朝上摆在一起，拍照上传。\n提交你的“心灵感应日记”模板：\n拍照上传你手绘的、空白的《心灵感应日记》表格。"},{"sequence":6,"day_label":"Day 6-7","day_range":"6-7","title_zh":"第一次“传心”练习","title_en":"The First 'Mind-Link' Practice","duration":"约30分钟，可在2天内完成","content":"(任务时长：约30分钟，可在2天内完成)\n探险家，你的工具箱已经准备就绪！现在，是时候进行我们第一次“心灵感应”练习了。\n寻找伙伴： 邀请一位家人（爸爸、妈妈或哥哥姐姐）和你一起玩这个游戏。\n分配角色： 第一次练习，建议你当“接收者”，家人当“发送者”。\n设置“实验室”：\n找两把椅子，背对背地放好。你们需要坐得足够近，可以相互接触，但绝对不能回头偷看！\n游戏开始：\n“发送者”（家人）：洗一下4张情绪闪卡，然后随机抽出一张，不要让你看到。\n专注“发送”（15-20秒）： “发送者”需要看着卡片上的情绪，闭上眼睛，非常非常努力地去感受这种情绪。如果抽到“开心”，就要努力回想最开心的事情。\n“接收者”（你）： 在这个时间里，你需要保持安静，放松下来，试着去**“听”**你内心升起的感觉。是感觉暖洋洋的？还是有点“堵”？\n做出你的猜测： 当“发送者”拍拍你的肩膀，示意时间到时，大声说出你“感觉”到的是哪种情绪。\n记录结果： “发送者”在《心灵感应日记》的“发送的情绪”一栏记录下真实的卡片，你在“我的猜测”一栏记录下你的猜测，然后一起判断结果是正确（✓）还是错误（✗）。\n进行10轮： 重复这个过程10次，完成你的第一份实验记录！\n亲身体验“排除感官干扰”（背对背坐）在实验中的重要性。\n学习如何将注意力从外部世界转向自己的内在感受。\n提交你的第一次实验记录：\n请拍照上传你和家人共同完成的、包含了10轮试验结果的《心灵感应日记》。\n分享你的初体验：\n在下方的文本框中，回答以下问题：\n问题1： 在10次猜测中，你猜对了几次？\n问题2： 在猜测时，你有什么特别的感觉吗？是脑海里出现了一种颜色，还是身体有某种感觉？或者只是凭直觉乱猜的？请描述一下。\n太棒了，心灵探险家！你已经成功地开启了你的第一次“心灵感应”探索之旅。无论你猜对了几次，这个过程本身就是一次奇妙的体验。从下周开始，我们将进行更大量的实验，并学习如何将你的“猜对率”与纯粹的“瞎猜”进行比较，看看你的“情绪天线”是不是真的比随机概率更强大！"}]},{"week":2,"theme":"信号还是噪音？——当科学遇上“运气”","days_range":"8-14","goals":["进行更多轮次的“传心”游戏，积累足够的数据量。学习基础的概率概念，特别是“随机概率基线”，并计算出在我们的实验中“瞎猜”的正确率应该是多少。将自己的实际正确率与概率基线进行对比，做出初步的科学判断。"],"activities":[{"sequence":8,"day_label":"Day 8-11","day_range":"8-11","title_zh":"数据大作战：完成50次“传心”挑战","title_en":"The Data Challenge: Completing 50 'Mind-Link' Trials","duration":"可在4天内，分为2-3次完成，每次约20-30分钟","content":"(任务时长：可在4天内，分为2-3次完成，每次约20-30分钟)\n心灵探险家，上周你完成了10次有趣的练习。但是，如果你只猜了10次就猜对了5次，我们能说你有“超能力”吗？也许只是运气好！\n为了知道这究竟是“信号”还是“运气”（在科学上我们称之为“噪音”），我们需要收集更多的数据。数据越多，“运气”的影响就越小，真实的“信号”就越容易显现出来。\n本周，你的任务是与你的家人伙伴一起，再完成至少40次“传心”游戏，使你的总试验次数达到50次！\n坚持游戏规则： 继续严格遵守我们上周制定的“传心”游戏规则。\n背对背，不许偷看！\n发送者先看卡，再专注感受。\n接收者先感受，再猜测。\n轮换角色（重要！）：\n为了让实验更有趣，也为了收集更全面的数据，请和你-的家人轮换角色。\n例如，今天你当20次“接收者”，明天你就可以当20次“发送者”，让你的家人来猜。看看谁的“情绪天线”更灵敏！\n在你的《心灵感应日记》中，一定要清晰地记录下每一轮谁是发送者，谁是接收者。\n系统记录：\n在你的日记本上，一轮一轮地、清晰地记录下每一次的“发送情绪”、“猜测”和“结果”。当你完成50次记录时，你的日记本看起来会非常壮观！\n通过大量的重复，亲身体会到：有时候你会连续猜对，有时候会连续猜错。这就是“随机性”的魅力。\n在扮演“发送者”时，更深入地体会如何将一种纯粹的情绪“发送”出去。你可能会发现，发送“生气”比发送“平静”更容易让对方接收到，或者反之。\n本周的核心作业将在周末（Day 12-14）统一提交。请确保在此之前完成至少40次新的试验记录。\n持续记录： 在你的《心灵感应日记》中，完成从第11次到第50次（或更多）的所有试验记录。"},{"sequence":12,"day_label":"Day 12-14","day_range":"12-14","title_zh":"科学的标尺：你的表现比“瞎猜”好吗？","title_en":"The Scientific Ruler: Are You Better Than a 'Random Guess'?","duration":"约60分钟，可在3天内完成","content":"(任务时长：约60分钟，可在3天内完成)\n探险家，你已经收集了50次宝贵的数据！现在，我们要学习如何用数学这把“尺子”，来衡量你的“超能力”到底有多强。\n首先，我们需要知道：如果一个人完全靠“瞎猜”，他能做对多少题？\n思想实验：\n想象一只聪明的小猴子，它不具备任何“心灵感应”能力。我们让它来玩我们的游戏。\n每次当“发送者”发送情绪后，我们就让小猴子从我们那4张“情绪闪卡”中，随机地抽出一张作为它的“猜测”。\n问题来了： 小猴子猜对的概率是多少？\n我们有4种可能的情绪（开心、伤心、生气、平静）。\n每一次，“发送者”发送的真实情绪只有1种。\n小猴子随机猜测，它猜中这1种正确情绪的可能性，就是四分之一。\n四分之一，用百分比表示就是 25% 。\n这个25%，就是我们这个实验的**“随机概率基线”（Random Chance Baseline）。它就像一把尺子上的“0”刻度。任何低于或等于这个数字的正确率，我们都可以认为是“运气”或“瞎猜”的结果。只有明显高于**这个数字，我们才能开始怀疑，这里面是不是有“心灵感应”的信号存在。\n那么，50次试验中，“瞎猜”应该对多少次呢？\n50次 × 25% = 50 × (1/4) = 12.5次\n所以，如果你的总正确次数在12次或13次左右，那就和小猴子差不多。但如果你的正确次数达到了20次，甚至30次，那就非常了不起了！\n统计你的总成绩：\n拿出你的《心灵感应日记》，仔细地数一数，在你作为**“接收者”**的所有试验中（例如，你总共猜了50次），你一共猜对了多少次（✓ 的数量）。\n计算你的正确率：\n公式： 正确率 = (你的正确次数 ÷ 你总共猜测的次数) × 100%\n例如，如果你猜了50次，猜对了15次，那么你的正确率就是 (15 ÷ 50) × 100% = 30%。\n与“猴子”比赛：\n将你的正确率，与25%的随机概率基线进行比较。你的表现比“瞎猜”好吗？好多少？\n掌握“概率基线”的概念，并能独立计算出我们实验中的随机正确率。\n学习如何将原始的计数数据，转化为更具比较意义的“百分比”。\n提交你的全部《心灵感应日记》：\n请将你记录了全部50次（或更多）试验的日记，清晰地拍照上传。\n提交你的“数据分析报告 V1.0”：\n在下方的文本框中，写下你的第一份数据分析报告。\n格式：\n标题： 我的“情绪天线”灵敏度测试报告\n总猜测次数： [例如：50] 次\n总正确次数： [例如：15] 次\n我的正确率： [例如：30]%\n随机概率基线： 25%\n我的初步结论： “我的正确率（30%）比随机瞎猜（25%）高出了5个百分点。这虽然不是一个巨大的领先，但它表明我的猜测可能不仅仅是运气。我对自己有‘情绪天线’这件事，增加了一点点信心！”\n（可选）提交家人的数据分析报告：\n如果你的家人也作为“接收者”进行了足够多的猜测，你也可以用同样的方法为他/她分析一次，看看谁更厉害！\n你已经成功地从一名探险家，升级为了一名“数据分析师”！探险家，你现在掌握了科学世界里最强大的武器之一——用数学和概率来对抗“偶然”。你不再仅仅是凭“感觉”说自己有超能力，而是可以用“数据”来证明你的感觉在多大程度上是可靠的。下周，我们将进行更深入的分析，看看你对哪种“情绪的颜色”最敏感，并开始制作你最终的成果报告！"}]},{"week":3,"theme":"颜色的解码——你对哪种情绪最敏感？","days_range":"15-21","goals":["学习“分类数据分析”的方法。对你的50次（或更多）实验数据进行分类统计，分别计算出你对“开心”、“伤心”、“生气”、“平静”这四种情绪的“接收”正确率。将分析结果用一张“情绪雷达图”进行可视化，并开始撰写最终报告的核心部分。"],"activities":[{"sequence":15,"day_label":"Day 15-18","day_range":"15-18","title_zh":"数据深潜：分类统计你的“情绪天线”","title_en":"Deep Data Dive: Categorizing Your 'Emotion Antenna'","duration":"约75分钟，可在4天内完成","content":"(任务时长：约75分钟，可在4天内完成)\n心灵探险家，上周我们得出了一个总的正确率。但是，你的“情绪天线”是不是对所有“频道”（情绪）的接收能力都一样呢？\n也许，你是一个非常善于感受他人“开心”的人，但对“生气”却不太敏感。或者，你对“平静”的感知力超乎常人！\n今天，我们就来当一名“信号解码员”，找出你最擅长接收的“情绪颜色”。\n准备你的“工作台”：\n拿出你记录了全部50次（或更多）试验的《心灵感应日记》。\n准备一张新的纸，或者打开一个电子表格。\n创建分类统计表：\n在新纸上，画出下面的表格。我们需要统计两组核心数据：每种情绪总共被发送了多少次，以及在这些发送中，你猜对了多少次。\n情绪分类统计表\n总发送次数\n我猜对的次数\n我的正确率 (%)\n开心    (黄色)\n \n \n \n伤心    (蓝色)\n \n \n \n生气    (红色)\n \n \n \n平静    (绿色)\n \n \n \n开始“解码”你的日记：\n逐条核对： 从你的第一条记录开始，逐一核对。\n划记统计（Tally Marks）：\n第一步：统计“总发送次数”。 看到第一条记录的“发送的情绪”是“开心”，就在表格中“开心”那一行的“总发送次数”格子里画一“正”字的一笔。看到第二条是“伤心”，就在“伤心”那行画一笔……以此类推，直到你核对完所有50条记录。\n第二步：统计“猜对的次数”。 再次从头开始。看到第一条记录是“开心”，并且结果是“✓”（正确），就在“开心”那一行的“我猜对的次数”格子里画一笔。如果结果是“✗”，则跳过。看到第三条是“生气”，结果是“✓”，就在“生气”那行画一笔……以此类推。\n计算分类正确率：\n当你完成所有划记后，将“正”字换算成阿拉伯数字。\n然后，为每一种情绪，单独计算你的正确率。\n公式： 分类正确率 = (该情绪的正确次数 ÷ 该情绪的总发送次数) × 100%\n例如，在你的50次试验中，“开心”总共被发送了12次，而你猜对了其中的6次，那么你对“开心”的正确率就是 (6 ÷ 12) × 100% = 50%。\n将计算出的四个正确率，分别填入表格的最后一列。\n掌握对原始数据进行“分类”和“筛选”的基本方法。\n学习如何进行更精细化的数据分析，从一个总体的、模糊的结论，走向更具体、更有洞察力的发现。\n提交你的《情绪分类统计表》：\n请拍照上传你手写的、填写完整的《情绪分类统计表》。确保表格中的所有数字都清晰可见。"},{"sequence":19,"day_label":"Day 19-21","day_range":"19-21","title_zh":"数据的艺术：绘制你的“情绪雷达图”","title_en":"The Art of Data: Plotting Your 'Emotion Radar'","duration":"约60分钟，可在3天内完成","content":"(任务时长：约60分钟，可在3天内完成)\n探险家，你手中的那张统计表充满了数字，但不够直观。现在，我们要用一种非常酷的图表——“雷达图”（Radar Chart），来让你对自己的“情绪天线”的强弱分布一目了然！\n雷达图就像一个游戏角色的“能力面板”，可以清晰地看出你在不同“属性”上的得分。\n选项A：纸笔绘制\n在纸上画一个大的十字，交叉点是中心。\n从中心点出发，向上、下、左、右画四条等长的线，形成四个“雷达轴”。\n在每个轴的末端，分别写上（或画上）四种情绪：上-开心  ，下-伤心  ，左-生气  ，右-平静  。\n在每个轴上，从中心（代表0%）到末端（代表100%），均匀地标出刻度，比如25%, 50%, 75%。特别地，用一条虚线连接四个轴的25%刻度点，形成一个正方形。这个虚线框，就是我们熟悉的“随机概率基线”。\n根据你上一份作业计算出的四种“分类正确率”，在每个对应的轴上找到相应的位置，并描一个点。\n最后，将这四个点依次连接起来，形成一个不规则的四边形。这个四边形，就是你独一无二的“情绪能力图谱”！它超出“随机基线框”越多的地方，就代表你对那种情绪的感知力越强。\n选项B：盖亚的图表生成器\n在下方输入你计算出的四种情绪的正确率：\n开心 (%): [ ]\n伤心 (%): [ ]\n生气 (%): [ ]\n平静 (%): [ ]\n[点击这里，生成我的情绪雷达图！] 盖亚会自动为你生成一张专业、美观的雷达图。\n学习雷达图这种多维度数据可视化工具的阅读和绘制方法。\n开始将你的数据发现，转化为最终报告的核心论点。\n提交你的“情绪雷达图”：\n如果你是手绘的，请拍照上传你的作品。\n如果你使用了盖亚生成器，请截图上传。\n提交你的“雷达图分析”与报告核心初稿：\n在下方的文本框中，写下你对雷达图的分析，并尝试将它扩展成你最终报告的**“结果”和“讨论”**部分的核心初稿。\n格式：\n手记标题： “我的情绪雷达：一个‘快乐’的接收者和一个‘平静’的盲人”\n我的雷达图分析（“结果”部分初稿）： “在总计50次试验中，我的整体正确率为30%。然而，分类数据显示了明显的非对称性（见图1：情绪雷达图）。我对‘开心’情绪的接收正确率达到了62.5%（8次中猜对5次），远高于25%的随机基线。我对‘生气’（33%）和‘伤心’（25%）的正确率则接近或等于随机水平。值得注意的是，我对‘平静’情绪的接收正确率为0%（14次中猜对0次），显著低于随机预期。”\n我的初步讨论（“讨论”部分初稿）： “这个雷达图揭示了我的‘情绪天线’可能存在特定的‘频道偏好’。我对高能量、积极的情绪（开心）似乎最为敏感，而对低能量、内敛的情绪（平静）则完全无法接收。这可能意味着，‘心灵感应’信号的强度或可辨识度，与情绪本身的‘能量振幅’有关。高能量情绪可能像一个大功率的广播电台，更容易被‘听到’。此外，完全无法感知‘平静’也为一个有趣的假说提供了可能：也许在心灵感应的‘频道’中，‘平静’的状态更接近于‘无信号’或‘静默’，因此难以被识别为一种积极的情绪信号。”\n你已经成为一名真正的数据侦探了！探险家，你不仅看到了宏观的图景，更深入到了数据的微观结构中，并从中提炼出了充满洞察力的、属于你自己的独特发现。这份雷达图和你对它的分析，将是你最终报告中最闪亮的核心。下周，我们将迎来这个项目的最后一周：整合你所有的发现，完成你的最终报告，并准备一个精彩的短视频，向世界分享你的“读心”之旅！"}]},{"week":4,"theme":"分享的色彩——讲述你的“心灵感应”故事","days_range":"22-28","goals":["整合所有实验数据、图表和分析，完成一份图文并茂的《我的“情绪天线”测试报告》。录制一个1-2分钟的短视频，生动地讲述你本次探索中最有趣的发现。获得“伊卡洛斯计划-心灵探险家”认证，为本次旅程画上圆满的句号。"],"activities":[{"sequence":22,"day_label":"Day 22-25","day_range":"22-25","title_zh":"最终报告的创作","title_en":"Crafting the Final Report","duration":"约90分钟，可在4天内完成","content":"(任务时长：约90分钟，可在4天内完成)\n心灵探险家，你已经完成了数据收集和深度分析的全部工作。现在，是时候将你所有的发现，汇集成一份可以永久珍藏的、精彩的最终报告了。\n你的《我的“情绪天线”测试报告》应该像一本有趣的科学绘本，它需要包含以下几个部分：\n第一部分：我的探险任务 (My Expedition Mission)\n内容：\n简要介绍“情绪的颜色”项目：我们想知道，人与人之间是否能不用语言就感受到对方的情绪？\n贴上你制作的**“情绪闪卡”**的照片，并介绍你的实验工具。\n第二部分：我的实验发现 (My Experimental Findings)\n内容：\n总体发现： 写下你的总猜测次数、总正确次数和总体正确率。并与25%的随机基线进行对比。\n深度发现： 贴上你上周绘制的“情绪雷达图”。这是你报告的核心！\n图表解读： 在雷达图旁边，用几句话清晰地解释你的发现。例如：“我的雷达图显示，我的‘天线’对‘开心’频道信号最好，正确率高达62.5%！但对‘平静’频道好像完全‘没信号’。”\n第三部分：一个神奇（或搞笑）的瞬间 (A Magical (or Funny) Moment)\n内容： 回顾你的《心灵感应日记》，挑选一次最让你印象深刻的“猜心”经历，把当时的故事详细地写下来。\n可以是一次不可思议的连续猜对，让你惊呼“有超能力！”\n也可以是一次特别搞笑的猜错，比如妈妈明明在想伤心的事，你却感觉她想吃冰淇淋。这些同样有趣！\n第四部分：我的探险家心得 (My Explorer's Reflection)\n内容： 这是你分享智慧的地方。请完成下面的句子：\n“通过这次‘心灵感应’实验，我最大的收获是……”\n“我发现，当我（或我的家人）在‘发送’……情绪时，好像特别容易被猜到，可能是因为……”\n“我认为，人和人之间的交流，除了说话，更重要的是用心去……”\n学习如何将数据、图表和个人故事，整合成一个有逻辑、有温度的完整报告。\n练习用孩子的语言，去解释相对复杂的概念（如正确率、雷达图）。\n提交你的《“情绪天线”测试报告》：\n请将你制作完成的、包含所有四个部分的完整报告，以拍照或截图的形式上传。\n我们强烈鼓励你用彩笔、贴纸等工具，让你的报告变得独一无二、充满创意！"},{"sequence":26,"day_label":"Day 26-28","day_range":"26-28","title_zh":"在镜头前分享：录制你的“探险家”视频","title_en":"Sharing on Camera: Recording Your 'Explorer' Video","duration":"约60分钟，可在3天内完成","content":"(任务时长：约60分钟，可在3天内完成)\n探险家，你已经完成了一份出色的书面报告。现在，让我们用一种更直接、更生动的方式，与全球的小伙伴们分享你的故事。你需要录制一个1-2分钟的短视频。\n你的视频可以很简单，用手机就能拍。但内容要充满你的个性和发现！\n视频“剧本”建议：\n开场（20秒）：\n出镜： 手里拿着你的“情绪闪卡”，向大家问好。\n台词： “大家好，我是心灵探险家[你的名字]！你相信人能‘读心’吗？在这四周里，我就和我的家人做了一个超酷的实验！”\n展示核心发现（60秒）：\n展示你的“王牌证据”： 将镜头对准你报告里的“情绪雷达图”。\n台词： “这是我的‘情绪天线’雷达图！你们看，中间这个框是‘瞎猜’的水平。我的总成绩比瞎猜要好一点点。但最神奇的是，看这里！（指着雷达图上最突出的角）我对‘开心’的感觉超级准，正确率超过了60%！但是，我对‘平静’好像完全接收不到信号。我猜，可能是因为‘开心’的能量像太阳一样，光芒四射；而‘平静’的能量像月光，太安静了，我的天线还不够灵敏！”（请根据你的真实结果来讲述）\n分享你的感悟（40秒）：\n出镜： 再次回到你的画面。\n台词： “这次实验让我觉得，有时候，用心去‘听’比用耳朵听更重要。也许我们每个人都有‘情绪天线’，只是平时太忙，忘记去使用了。你也和你的家人试试看吧！谢谢大家！”\n学习如何将一份报告的核心内容，浓缩成一个简短、有趣、有观点的口头演讲。\n练习在镜头前自信、自然地进行表达和分享。\n上传你的“探险家分享视频”：\n请将你录制好的1-2分钟短视频文件上传。\n提交你的结业宣言与认证：\n当你的视频上传后，盖亚将自动为你颁发**“伊卡洛斯计划 - 心灵探险家”**的电子认证徽章。\n请将你的认证徽章截图上传，并在下方的“结业留言板”写下你的最终感言。\n格式： “我是心灵探险家[你的名字]。我的‘情绪天线’对‘开心’最敏感！我最大的收获是，科学不仅在实验室里，也在我和妈妈背对背坐着、感受彼此心跳的游戏里。#伊卡洛斯毕业#”\n伟大的心灵探险家，为你欢呼！你不仅完成了一次充满乐趣的科学实验，更重要的是，你开启了一段与家人之间全新的、深刻的连接方式。你用自己的实践证明了，即使是孩子，也可以用严谨的方法去探索那些最神秘、最温暖的人类体验。你所分享的每一个数据和微笑，都将激励更多的人去重新发现我们与生俱来的、超越语言的共情能力。期待在下一个更具挑战的模块中，与你重逢！"}]}]$week_data$::jsonb
WHERE system_id = '9da7c347-fe63-4c81-81e1-df576bcd2e6c'::uuid
  AND sequence_number = 8;

-- 验证更新
SELECT
  sequence_number,
  title,
  jsonb_array_length(week_plan) as weeks_count,
  (
    SELECT COUNT(*)
    FROM jsonb_array_elements(week_plan) w,
         jsonb_array_elements(w->'activities') a
  ) as activities_count
FROM course_contents
WHERE system_id = '9da7c347-fe63-4c81-81e1-df576bcd2e6c'::uuid
  AND sequence_number = 8;
